// Semana anterior completa, segunda a domingo, no fuso de São Paulo
const agora = DateTime.now().setZone('America/Sao_Paulo');
const inicioSemana = agora.startOf('week').minus({ weeks: 1 }); // luxon: semana começa na segunda
const fimSemana = inicioSemana.plus({ days: 6 });

return [{
  json: {
    inicio: inicioSemana.toFormat('yyyy-MM-dd'),
    fim: fimSemana.toFormat('yyyy-MM-dd'),
    rotulo: `${inicioSemana.toFormat('dd/MM/yyyy')} a ${fimSemana.toFormat('dd/MM/yyyy')}`,
  }
}];

const periodo = $('Calcular Período').first().json;
const kpis = $('KPIs Semana').first().json ?? {};
const dias = $('Série Diária').all().map(i => i.json).filter(r => r && r.dia);
const ranking = $('Ranking Representantes').all().map(i => i.json).filter(r => r && r.representante);
const handoffs = $('Lista Handoffs').all().map(i => i.json).filter(r => r && r.data_handoff);
const intl = $('Internacional').first().json ?? {};

const esc = s => String(s ?? '').replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
const num = n => Number(n ?? 0).toLocaleString('pt-BR');
const fmtDia = iso => DateTime.fromISO(String(iso)).setLocale('pt-BR').toFormat('ccc dd/MM');
const fmtDataHora = iso => DateTime.fromISO(String(iso)).setZone('America/Sao_Paulo').toFormat('dd/MM HH:mm');

const thStyle = 'style="background:#82181c;color:#fff;padding:6px 8px;text-align:left;font-size:12px;white-space:nowrap"';
const tdStyle = 'style="padding:6px 8px;border-bottom:1px solid #eee;font-size:12px"';
const tabela = inner =>
  `<div style="overflow-x:auto;-webkit-overflow-scrolling:touch;margin:8px 0 24px">` +
  `<table style="border-collapse:collapse;width:100%">${inner}</table></div>`;

const kpiCard = (titulo, valor) =>
  `<div style="display:inline-block;vertical-align:top;min-width:128px;margin:4px;padding:12px 14px;background:#faf7f5;border:1px solid #eee;border-radius:8px;text-align:center">` +
  `<div style="font-size:12px;color:#777">${titulo}</div>` +
  `<div style="font-size:22px;font-weight:bold;color:#1d1d1d">${valor}</div></div>`;

const blocoKpis = `<div style="text-align:center;margin:8px 0 16px">` +
  kpiCard('Novos atendimentos', num(kpis.novos_atendimentos)) +
  kpiCard('Conversas ativas', num(kpis.conversas_ativas)) +
  kpiCard('Transferidos', num(kpis.transferidos)) +
  kpiCard('Taxa de transferência', String(kpis.taxa_transferencia ?? 0).replace('.', ',') + '%') +
  kpiCard('Internacionais', num(kpis.internacionais)) +
  `</div>`;

const blocoDias = dias.length
  ? tabela(`<tr><th ${thStyle}>Dia</th><th ${thStyle}>Novos</th><th ${thStyle}>Ativos</th><th ${thStyle}>Transferidos</th></tr>` +
      dias.map(d => `<tr><td ${tdStyle}>${fmtDia(d.dia)}</td><td ${tdStyle}>${num(d.novos)}</td><td ${tdStyle}>${num(d.ativos)}</td><td ${tdStyle}>${num(d.transferidos)}</td></tr>`).join(''))
  : '<p style="color:#777">Sem dados diários no período.</p>';

const blocoRanking = ranking.length
  ? tabela(`<tr><th ${thStyle}>Representante</th><th ${thStyle}>Telefone</th><th ${thStyle}>Transf.</th><th ${thStyle}>Última</th></tr>` +
      ranking.map(r => `<tr><td ${tdStyle}>${esc(r.representante)}</td><td ${tdStyle}>${esc(r.telefone_representante)}</td><td ${tdStyle}>${num(r.total)}</td><td ${tdStyle}>${fmtDataHora(r.ultima_transferencia)}</td></tr>`).join(''))
  : '<p style="color:#777">Nenhuma transferência no período.</p>';

const MAX_HANDOFFS = 40;
const blocoHandoffs = handoffs.length
  ? tabela(`<tr><th ${thStyle}>Data</th><th ${thStyle}>Cliente</th><th ${thStyle}>Telefone</th><th ${thStyle}>Representante</th><th ${thStyle}>Região</th><th ${thStyle}>Tipo</th><th ${thStyle}>Motivo</th></tr>` +
      handoffs.slice(0, MAX_HANDOFFS).map(h => `<tr><td ${tdStyle}>${fmtDataHora(h.data_handoff)}</td><td ${tdStyle}>${esc(h.nome_cliente ?? '—')}</td><td ${tdStyle}>${esc(h.telefone_cliente)}</td><td ${tdStyle}>${esc(h.representante)}</td><td ${tdStyle}>${esc(h.regiao ?? '—')}</td><td ${tdStyle}>${esc(h.tipo_cliente ?? '—')}</td><td ${tdStyle}>${esc(h.motivo ?? '—')}</td></tr>`).join('')) +
    (handoffs.length > MAX_HANDOFFS ? `<p style="color:#777;font-size:12px">Mostrando ${MAX_HANDOFFS} de ${handoffs.length} transferências — lista completa no dashboard.</p>` : '')
  : '<p style="color:#777">Nenhuma transferência no período.</p>';

const porPais = Array.isArray(intl.por_pais) ? intl.por_pais : [];
const blocoIntl = (intl.total ?? 0) > 0
  ? `<p style="font-size:13px"><strong>${num(intl.total)}</strong> atendimento(s) internacional(is): ` +
    porPais.map(p => `${esc(p.pais)} (${num(p.total)})`).join(', ') + `</p>`
  : '<p style="color:#777">Nenhum atendimento internacional no período.</p>';

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"></head>` +
  `<body style="font-family:Arial,Helvetica,sans-serif;color:#1d1d1d;max-width:680px;width:100%;margin:0 auto;padding:12px;box-sizing:border-box">` +
  `<div style="background:#1d1d1d;padding:14px 16px;border-radius:8px 8px 0 0">` +
  `<h1 style="color:#fff;font-size:17px;margin:0">Relatório semanal — Atendimento WhatsApp INTT</h1>` +
  `<p style="color:#a7815c;font-size:13px;margin:4px 0 0">Semana de ${periodo.rotulo}</p></div>` +
  `<div style="border:1px solid #eee;border-top:0;border-radius:0 0 8px 8px;padding:12px 16px">` +
  `<h2 style="font-size:15px;color:#82181c">Resumo da semana</h2>` + blocoKpis +
  `<h2 style="font-size:15px;color:#82181c">Dia a dia</h2>` + blocoDias +
  `<h2 style="font-size:15px;color:#82181c">Ranking de representantes</h2>` + blocoRanking +
  `<h2 style="font-size:15px;color:#82181c">Transferências da semana</h2>` + blocoHandoffs +
  `<h2 style="font-size:15px;color:#82181c">Internacional</h2>` + blocoIntl +
  `<p style="color:#999;font-size:11px;margin-top:24px">Gerado automaticamente pelo n8n a partir do Supabase.</p>` +
  `</div></body></html>`;

return [{
  json: {
    subject: `Relatório semanal atendimento WhatsApp — ${periodo.rotulo}`,
    html,
  }
}];
